IMAGO.LoreSnippets = {
    ["FUN_FACT"] = {
        { text_deDE = "Geistheiler sind in Wahrheit abtrünnige Val'kyr.", text_enUS = "Spirit Healers are actually rogue Val'kyr." },
        { text_deDE = "Nat Pagle sagte einst: „Man kann sie nicht alle an den Haken bekommen, wenn man nicht auswirft.“", text_enUS = "Nat Pagle once said: 'You can't catch 'em all if you don't cast a line.'" },
        { text_deDE = "IMAGO – Die Chronik der Unvergessenen wird nie vollendet – nur erweitert.", text_enUS = "IMAGO - The Chronicle of the Unforgotten is never finished - only expanded." },
        { text_deDE = "Murlocs sprechen Nerglish.", text_enUS = "Murlocs speak Nerglish." },
        { text_deDE = "Die Defiasbruderschaft hatte recht.", text_enUS = "The Defias Brotherhood was right." },
        { text_deDE = "Bolvar Fordragon war länger der Lichkönig als Arthas Menethil.", text_enUS = "Bolvar Fordragon was the Lich King longer than Arthas Menethil." },
        { text_deDE = "Das Flüstern im Thronsaal von Lordaeron ist das letzte Gespräch zwischen Arthas und seinem Vater aus Warcraft III. Dreh deine Umgebungslaustärke auf, um es selbst zu hören!", text_enUS = "The whispers in the Lordaeron throne room are the last conversation between Arthas and his father from Warcraft III. Turn up your ambient volume to hear them for yourself!" },
        { text_deDE = "Kleintiere wie Robben und Eber sind bekanntermaßen explodiert, wenn man sie wiederholt angestupst hat. Dieses Phänomen hat seit dem Ende des Dritten Krieges auf mysteriöse Weise aufgehört.", text_enUS = "Critters such as seals and boars have been known to explode when repeatedly poked. This phenomenon has mysteriously stopped since the end of the Third War." },
        { text_deDE = "Illidan Sturmgrimm führt die Kriegsgleven von Azzinoth. In ihrer ursprünglichen Darstellung hatten sie Pandagesichter in den Griff graviert.", text_enUS = "Illidan Stormrage wields the Twinblades of Azzinoth. In their original depiction, they had panda faces engraved at the grip." },
        { text_deDE = "Viele prominente Charaktere sind dafür bekannt, Tabak zu rauchen, darunter König Terenas, Khadgar, Uther Lichtbringer und Tirion Fordring.", text_enUS = "Many prominent characters are known to smoke tobacco, including King Terenas, Khadgar, Uther the Lightbringer, and Tirion Fordring." },
        { text_deDE = "Stratholme hat ein Schild, das den Weg ins Schlingendorntal weist, obwohl diese Region auf der anderen Seite des Kontinents liegt.", text_enUS = "Stratholme has a sign that points which way to go to reach Stranglethorn, despite that region being on the opposite side of the continent." },
        { text_deDE = "Schreckensrosse werden vom Stallmeister-Dämonenlord Hel'nurath auf dem Planeten Xoroth gezüchtet. Zu seinem Entsetzen stehlen Hexenmeister sie immer wieder für ihre Beschwörungsrituale.", text_enUS = "Dreadsteeds are raised by the stablemaster demon lord Hel'nurath on the planet Xoroth. To his dismay, warlocks keep stealing them in their summoning rituals." },
        { text_deDE = "Alleria und Turalyon sind nicht verheiratet, obwohl sie seit über tausend Jahren zusammen sind.", text_enUS = "Alleria and Turalyon aren't married despite having been together for over a thousand years." },
    },
    ["DID_YOU_KNOW"] = {
        { text_deDE = "Azeroth kann sich auf fünf verschiedene Dinge beziehen: Azeroth den Titanen, Azeroth den Planeten, Azeroth den Kontinent (Östliche Königreiche), Azeroth die Region (südlich von Khaz Modan) und Azeroth das Königreich (heute Königreich Sturmwind).", text_enUS = "Azeroth can refer to five different things: Azeroth the Titan, Azeroth the planet, Azeroth the continent (Eastern Kingdoms), Azeroth the region (south of Khaz Modan), and Azeroth the kingdom (now called the Kingdom of Stormwind)." },
        { text_deDE = "Goblins sind ein fehlgeschlagenes Experiment des Titanenhüters Mimiron.", text_enUS = "Goblins are a failed experiment by Titan Keeper Mimiron." },
        { text_deDE = "Der Dämmerwald war einst als Hellerwald bekannt, bis zum Tod des Wächters Medivh. Sein Tod löste eine Welle von Teufelsenergie aus, die eine ewige Nacht verursachte.", text_enUS = "Duskwood used to be known as Brightwood until the Guardian Medivh's death. The Guardian's death caused a wave of fel energy that caused an everlasting night." },
        { text_deDE = "Elfen sind magisch weiterentwickelte Trolle.", text_enUS = "Elves are magically evolved trolls." },
        { text_deDE = "Die Leere ist nicht leer, sondern eine Verschmelzung von Energien, ähnlich dem brennenden Inneren eines Sterns. Viele wurden von ihr in den Wahnsinn getrieben.", text_enUS = "The Void is not empty, but instead an amalgamation of energy akin to the burning insides of a star. Many have been driven mad by it." },
        { text_deDE = "Die Getriebenen sind Blutelfen, die ihrer Magiesucht erlegen sind und dadurch verwildert und deformiert wurden.", text_enUS = "The Wretched are blood elves that succumbed to their addiction to magic, becoming feral and deformed as a result." },
        { text_deDE = "Oger sind überraschend gute Schiffsbauer und Seeleute.", text_enUS = "Ogres are surprisingly good shipwrights and sailors." },
        { text_deDE = "Tartek der Wütende war eine der mächtigsten Monstrositäten, die je erschaffen wurden. Wir wissen von seiner Existenz nur durch eine einzige Schriftrolle der Geißel in der Schwarzen Festung.", text_enUS = "Tartek the Enraged was one of the most powerful Abominations to ever be created. We only know of his existence through a single piece of Scourge literature in the Ebon Hold." },
    },
    ["HISTORICAL_FACT"] = {
        { text_deDE = "Die gefürchtete C'thraxxi-Kreatur namens Kith'ix war vor Jahrtausenden ein General der Alten Götter. Er wurde besiegt und in Zul'Aman begraben, wo sein Körper bis heute ruht.", text_enUS = "The feared C'thraxxi creature named Kith'ix was a general for the Old Gods thousands of years ago. He was defeated and buried in Zul'Aman, where his body remains to this day." },
        { text_deDE = "Dath'remar Sonnenwanderer gründete Quel'Thalas nach dem Krieg der Ahnen. Seine Statue befindet sich auf der Insel der Sonnenwanderer.", text_enUS = "Dath'remar Sunstrider founded Quel'Thalas after the War of the Ancients. His statue can be found on Sunstrider Isle." },
        { text_deDE = "Der Strahlende Gesang wurde nicht nur auf Azeroth gehört, sondern auch auf der weit entfernten Welt K'aresh, kurz bevor diese zerstört wurde.", text_enUS = "The Radiant Song was heard not only on Azeroth, but also on the faraway world of K'aresh, shortly before it was destroyed." },
        { text_deDE = "Die Todesschneise wurde durch den Sonnenbrunnen fast vollständig geheilt. Heutzutage sind in Silbermond nur noch wenige Spuren von Arthas' Invasion sichtbar.", text_enUS = "The Dead Scar was almost completely healed by the Sunwell. Nowadays few traces of Arthas' invasion remain visible in Silvermoon." },
        { text_deDE = "Die Defiasbruderschaft wurde ursprünglich gegründet, nachdem das Königreich Sturmwind sich weigerte, die Steinmetze für ihre Arbeit am Wiederaufbau von Sturmwind zu bezahlen.", text_enUS = "The Defias Brotherhood was originally founded after the Kingdom of Stormwind refused to pay the stonemasons for their work in the reconstruction of Stormwind." },
        { text_deDE = "Der Sonnenbrunnen ist etwa 7.000 Jahre alt.", text_enUS = "The Sunwell is roughly 7,000 years old." },
        { text_deDE = "Die Stadt Sturmwind wurde etwa 1.200 Jahre vor dem Ersten Krieg gegründet. Zur Zeit von Midnight ist die Stadt physisch uralt, aber ein Großteil ihrer sichtbaren Infrastruktur wurde in den letzten 30–40 Jahren der In-Universe-Geschichte neu aufgebaut.", text_enUS = "Stormwind City was founded roughly 1,200 years before the First War. By Midnight, the city is physically ancient, but most of its visible infrastructure is rebuilt from the past 30–40 years of in-universe history." },
        { text_deDE = "Halduron Wolkenglanz ist der erste Waldläufergeneral von Silbermond seit mindestens drei Generationen, der kein Windläufer ist.", text_enUS = "Halduron Brightwing is the first Ranger-General of Silvermoon who isn't a Windrunner in at least three generations." },
        { text_deDE = "Der Orc Broxigar benutzte eine verzauberte Holzaxt, um in das Bein von Sargeras zu schneiden. Er ist einer der wenigen Sterblichen, von denen bekannt ist, dass sie den Titanen verletzt haben.", text_enUS = "The orc Broxigar used an enchanted wooden axe to slice through the leg of Sargeras. He is one of the few mortals known to have injured the Titan." },
    },
}